htmx.defineExtension("amz-content-sha256",{init:function(){return this.RequestHashQueue={},this.calculateSHA256=async e=>{const t=(new TextEncoder).encode(e),n=await crypto.subtle.digest("SHA-256",t);return Array.from(new Uint8Array(n)).map((e=>e.toString(16).padStart(2,"0"))).join("")},null},onEvent:async function(e,t){switch(e){case"htmx:confirm":const e=t.target;t.preventDefault();const n=e=>Array.from(e.entries()).map((([e,t])=>encodeURIComponent(e)+"="+encodeURIComponent(t))).join("&");let a="";if(e instanceof HTMLFormElement){a=n(new FormData(e))}else{const t=[],n=e.getAttribute("hx-include");let s=null;if("this"===n||"closest this"===n)if(e instanceof HTMLInputElement||e instanceof HTMLSelectElement||e instanceof HTMLTextAreaElement)e.name&&t.push([e.name,e.value]);else if(e instanceof HTMLFormElement){new FormData(e).forEach(((e,n)=>t.push([n,e])))}else{e.querySelectorAll("input, select, textarea").forEach((e=>{e.name&&t.push([e.name,e.value])}))}else if(n){document.querySelectorAll(n).forEach((e=>{if(e instanceof HTMLFormElement){new FormData(e).forEach(((e,n)=>t.push([n,e])))}else if(e instanceof HTMLInputElement||e instanceof HTMLSelectElement||e instanceof HTMLTextAreaElement)e.name&&t.push([e.name,e.value]);else{e.querySelectorAll("input, select, textarea").forEach((e=>{e.name&&t.push([e.name,e.value])}))}}))}else if(s=e.closest("form"),s){new FormData(s).forEach(((e,n)=>t.push([n,e])))}const o=e.getAttribute("hx-vals");if(o)try{const e=JSON.parse(o);for(const[n,a]of Object.entries(e)){for(let e=t.length-1;e>=0;e--)t[e][0]===n&&t.splice(e,1);t.push([n,a])}}catch(e){console.warn("amz-content-sha256: Failed to parse hx-vals",e)}a=t.map((([e,t])=>encodeURIComponent(e)+"="+encodeURIComponent(t))).join("&")}const s=await this.calculateSHA256(a);this.RequestHashQueue[t.detail.path]?this.RequestHashQueue[t.detail.path].push(s):this.RequestHashQueue[t.detail.path]=[s];const o=e.getAttribute("hx-confirm");o?confirm(o)&&t.detail.issueRequest(!0):t.detail.issueRequest(!0);break;case"htmx:configRequest":this.RequestHashQueue[t.detail.path]?.length>0&&(t.detail.headers["x-amz-content-sha256"]=this.RequestHashQueue[t.detail.path].pop())}}});